interface1 = 50;interface2 = 50;interface3 = 50;interface4 = 50;load_p = 1e3;NR = 1e-3;i = 1;powersysModel = "transmission_system";Interface = [30, 60, 90];NR_values = [1e-3, 0.032, 0.422];Load = [0.8*1e3, 1e3, 1.2*1e3];open_system(powersysModel)myfaults = Simulink.fault.findFaults(powersysModel);names = {myfaults.Name};% Use regex to extract the digits from 'Fault1', 'Fault2', etc.nums = regexp(names, '\d+', 'match', 'once');nums = str2double(nums);% 3. Sort based on those numbers[~, sortIdx] = sort(nums);myfaults = myfaults(sortIdx);for f = 1:14    if f <12        Fault = sprintf('Fault%d', f);        for NR = NR_values            for load_p = Load                for interface1 = Interface                    Simulink.fault.enable(powersysModel+"/Transmission Line(Three-Phase)/Section interface", true);                    activate(myfaults(f));                    out = sim(powersysModel);                    Simulink.fault.enable(powersysModel+"/Transmission Line(Three-Phase)/Section interface", false);                    Vabc = squeeze(out.logsout.get('Vabc').Values.Data);                    Iabc = squeeze(out.logsout.get('Iabc').Values.Data);                    VI = [Vabc; Iabc];                    T_transient = array2table(VI', 'VariableNames', {'Va', 'Vb', 'Vc', 'Ia', 'Ib', 'Ic'});                    % 2. Create the "Summary Row" for this                     % We wrap T_transient in { } to tell M                    T_mini = table({T_transient}, 'VariableNames', {'TransientData'});                    T_mini.FaultID = repmat(Fault, height(T_mini), 1);                    T_mini.Interface = repmat(interface1, height(T_mini), 1);                    storage_bucket{i} = T_mini;                    i = i + 1;                end            end        end    elseif (11 < f) && (f < 23)        Fault = sprintf('Fault%d', f);        for NR = NR_values            for load_p = Load                for interface2 = Interface                    Simulink.fault.enable(powersysModel+"/Transmission Line(Three-Phase)1/Section interface", true);                    activate(myfaults(f));                    out = sim(powersysModel);                    Simulink.fault.enable(powersysModel+"/Transmission Line(Three-Phase)1/Section interface", false);                    Vabc = squeeze(out.logsout.get('Vabc').Values.Data);                    Iabc = squeeze(out.logsout.get('Iabc').Values.Data);                    VI = [Vabc; Iabc];                    T_transient = array2table(VI', 'VariableNames', {'Va', 'Vb', 'Vc', 'Ia', 'Ib', 'Ic'});                    % 2. Create the "Summary Row" for this                     % We wrap T_transient in { } to tell M                    T_mini = table({T_transient}, 'VariableNames', {'TransientData'});                    T_mini.FaultID = repmat(Fault, height(T_mini), 1);                    T_mini.Interface = repmat(interface2, height(T_mini), 1);                    storage_bucket{i} = T_mini;                    i = i + 1;                end            end        end    elseif (22 < f) && (f < 34)        Fault = sprintf('Fault%d', f);        for NR = NR_values            for load_p = Load                for interface3 = Interface                    Simulink.fault.enable(powersysModel+"/Transmission Line(Three-Phase)1/Section interface", true);                    activate(myfaults(f));                    out = sim(powersysModel);                    Simulink.fault.enable(powersysModel+"/Transmission Line(Three-Phase)1/Section interface", false);                    Vabc = squeeze(out.logsout.get('Vabc').Values.Data);                    Iabc = squeeze(out.logsout.get('Iabc').Values.Data);                    VI = [Vabc; Iabc];                    T_transient = array2table(VI', 'VariableNames', {'Va', 'Vb', 'Vc', 'Ia', 'Ib', 'Ic'});                    % 2. Create the "Summary Row" for this                     % We wrap T_transient in { } to tell M                    T_mini = table({T_transient}, 'VariableNames', {'TransientData'});                    T_mini.FaultID = repmat(Fault, height(T_mini), 1);                    T_mini.Interface = repmat(interface3, height(T_mini), 1);                    storage_bucket{i} = T_mini;                    i = i + 1;                end            end        end    else        Fault = sprintf('Fault%d', f);        for NR = NR_values            for load_p = Load                for interface4 = Interface                    Simulink.fault.enable(powersysModel+"/Transmission Line(Three-Phase)1/Section interface", true);                    activate(myfaults(f));                    out = sim(powersysModel);                    Simulink.fault.enable(powersysModel+"/Transmission Line(Three-Phase)1/Section interface", false);                    Vabc = squeeze(out.logsout.get('Vabc').Values.Data);                    Iabc = squeeze(out.logsout.get('Iabc').Values.Data);                    VI = [Vabc; Iabc];                    T_transient = array2table(VI', 'VariableNames', {'Va', 'Vb', 'Vc', 'Ia', 'Ib', 'Ic'});                    % 2. Create the "Summary Row" for this                     % We wrap T_transient in { } to tell M                    T_mini = table({T_transient}, 'VariableNames', {'TransientData'});                    T_mini.FaultID = repmat(Fault, height(T_mini), 1);                    T_mini.Interface = repmat(interface4, height(T_mini), 1);                    storage_bucket{i} = T_mini;                    i = i + 1;                end            end        end    endendSimulink.fault.save(powersysModel);close_system(powersysModel);